const item = $input.first().json;
const body = item.body || item;
const params = body.params || body;
const fileId = params.photo_file_id || params.file_id || body.photo_file_id || body.file_id || '';
const caption = params.prompt || params.photo_caption || params.caption || body.prompt || body.photo_caption || body.caption || '';
const chatId = params.photo_chat_id || params.chat_id || params.chatId || body.photo_chat_id || body.chat_id || body.chatId || '';

if (!fileId) {
  throw new Error('Không tìm thấy file_id ảnh sản phẩm. Vui lòng gửi ảnh kèm caption mô tả hoặc reply vào ảnh có sẵn.');
}

return [{
  json: {
    file_id: fileId,
    caption: caption,
    chat_id: String(chatId),
    source: params.source || body.source || 'telegram'
  }
}];

// Read Telegram photo binary via n8n RPC helper, then build the official Veo REST image-to-video body.
const request = $node['Normalize Video Request'].json;
const chatId = request.chat_id;
const caption = request.caption || '';

const input = $input.first();
const binaryKey = Object.keys(input.binary || {})[0] || 'data';
if (!input.binary?.[binaryKey]) {
  throw new Error('Không tìm thấy dữ liệu ảnh nhị phân từ Telegram.');
}

const buffer = await helpers.getBinaryDataBuffer(0, binaryKey);
const photoBase64 = buffer.toString('base64');
if (!photoBase64 || photoBase64.length < 100) {
  throw new Error('Ảnh tải từ Telegram rỗng hoặc không hợp lệ.');
}

let photoMime = input.binary[binaryKey].mimeType || 'image/jpeg';
if (photoMime === 'application/octet-stream') {
  if (photoBase64.startsWith('/9j/')) photoMime = 'image/jpeg';
  else if (photoBase64.startsWith('iVBOR')) photoMime = 'image/png';
  else if (photoBase64.startsWith('UklG')) photoMime = 'image/webp';
  else photoMime = 'image/jpeg';
}

const wantsCatwalk = /catwalk|trình diễn|sải bước/i.test(caption);
const wantsOrbit = /orbit|xoay|360/i.test(caption);
const wantsWindy = /windy|gió|bay/i.test(caption);
const wantsLifestyle = /lifestyle|đời thường|phố|café/i.test(caption);

let cleanCaption = caption.replace(/^🎬\s*(Dựng video AI|tạo video)\s*/i, '').trim();
cleanCaption = cleanCaption.replace(/catwalk|orbit|windy|lifestyle/gi, '').replace(/\s+/g, ' ').trim();

const p = [];
p.push('Cinematic high-fashion video advertisement.');
p.push('Use the input clothing product image as the first frame and preserve the exact garment structure, color, print, texture, and fit throughout the video.');

if (wantsCatwalk) {
  p.push('A gorgeous professional fashion model confidently walks down a bright runway, showcasing the flow, movement, and details of the outfit. Slow zoom out, elegant warm lighting.');
} else if (wantsOrbit) {
  p.push('A slow, smooth 360-degree camera orbit around the model standing in a sleek minimalist modern studio, showcasing every side and fit of the garment. Even soft lighting.');
} else if (wantsWindy) {
  p.push('A slow-motion medium shot of the model standing while a gentle natural breeze makes the fabric, sleeves, and train sway beautifully, emphasizing light airy texture.');
} else if (wantsLifestyle) {
  p.push('The model walks gracefully in a bright modern cafe interior with sunlight through large windows, cozy warm atmosphere, and soft depth-of-field background blur.');
} else {
  p.push('A professional model wearing this outfit moves elegantly in a high-end fashion shoot. Slow motion, side-to-side camera pan, warm cinematic lighting, high-fidelity garment details.');
}

if (cleanCaption && cleanCaption.length > 2) {
  p.push('Additional user directions: ' + cleanCaption);
}

p.push('Ultra-realistic, 720p, professional color grading. No text, watermark, subtitles, logos, or graphic overlays.');

return [{
  json: {
    chat_id: chatId,
    clean_caption: cleanCaption || 'Video quảng cáo thời trang chuyên nghiệp',
    veo_body: {
      instances: [{
        prompt: p.join(' '),
        image: {
          bytesBase64Encoded: photoBase64,
          mimeType: photoMime
        }
      }],
      parameters: {
        aspectRatio: '9:16',
        durationSeconds: 8,
        personGeneration: 'allow_all'
      }
    }
  }
}];

const res = $input.first().json;
if (!res.name) {
  throw new Error('API không trả về tên Operation. Lỗi: ' + JSON.stringify(res));
}
return [{
  json: {
    chat_id: $node['Build Prompt and Base64'].json.chat_id,
    operation_name: res.name,
    counter: 0,
    done: false
  }
}];

const res = $input.first().json;
const prevState = $node['Wait 15s'] ? $node['Wait 15s'].json : $node['Initialize Polling'].json;
const counter = (prevState.counter || 0) + 1;
const isDone = res.done === true;

let videoUri = '';
let errorMessage = '';

if (isDone) {
  if (res.error) {
    errorMessage = 'Lỗi từ Google Veo: ' + (res.error.message || JSON.stringify(res.error));
  } else {
    videoUri = res.response?.generateVideoResponse?.generatedSamples?.[0]?.video?.uri || '';
    if (!videoUri) {
      errorMessage = 'Không tìm thấy URI video trong phản hồi thành công.';
    }
  }
} else if (counter >= 20) {
  errorMessage = 'Thời gian xử lý video vượt quá giới hạn (5 phút). Vui lòng thử lại sau.';
}

return [{
  json: {
    chat_id: prevState.chat_id,
    operation_name: prevState.operation_name,
    counter: counter,
    done: isDone,
    video_uri: videoUri,
    error_message: errorMessage
  }
}];

// Save the freshly generated video URI for this chat so the Telegram Gateway can pick it up
// when the user says things like 'dang video nay len fanpage' right after the bot returns the video.
const item = $input.first().json;
const chatId = String(item.chat_id || '');
const videoUri = String(item.video_uri || '');
const caption = String($node['Build Prompt and Base64']?.json?.clean_caption || '');
if (!chatId || !videoUri) {
  return [{ json: { ...item, saved: false } }];
}
const fs = require('fs');
const path = require('path');
const filePath = path.join($env.N8N_USER_FOLDER || './.n8n', 'recent_videos.json');
let store = { videos: {} };
try {
  if (fs.existsSync(filePath)) store = JSON.parse(fs.readFileSync(filePath, 'utf8'));
} catch (e) { store = { videos: {} }; }
store.videos = store.videos || {};
const list = store.videos[chatId] || [];
list.push({
  video_uri: videoUri,
  caption: caption,
  created_at: new Date().toISOString()
});
store.videos[chatId] = list.slice(-5);
try {
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  fs.writeFileSync(filePath, JSON.stringify(store, null, 2), 'utf8');
} catch (e) { /* fallback to static */ }
return [{ json: { ...item, saved: true, video_uri: videoUri, chat_id: chatId } }];

